{
  "intro": "You're a dispatcher for a global digital courier. A massive file needs to reach a client across the ocean, and the routes are shifting every second.",
  "metrics": [
    "Speed",
    "Reliability",
    "Infrastructure"
  ],
  "steps": [
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "The smaller pieces weave through traffic easily. Each one moves independently toward the goal.",
          "id": "s1_a",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Speed"
            },
            {
              "effect": "positive",
              "metric": "Reliability"
            }
          ],
          "text": "Break the file into small, uniform envelopes"
        },
        {
          "alignment": "partial",
          "consequence": "One box gets stuck in a narrow alleyway. The client receives half the file and can't use it.",
          "id": "s1_b",
          "metricEffects": [
            {
              "effect": "neutral",
              "metric": "Speed"
            },
            {
              "effect": "negative",
              "metric": "Reliability"
            }
          ],
          "text": "Divide it into two large, heavy crates"
        },
        {
          "alignment": "weak",
          "consequence": "The massive crate is rejected at the first checkpoint for being too big. Nothing moves.",
          "id": "s1_c",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Speed"
            },
            {
              "effect": "negative",
              "metric": "Reliability"
            }
          ],
          "text": "Send the entire file in one giant container"
        }
      ],
      "situation": "A high-resolution video file is ready to send. It's too large for a single delivery run."
    },
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "If an envelope gets separated, any courier can still find the way. No data is lost.",
          "id": "s2_a",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Reliability"
            },
            {
              "effect": "negative",
              "metric": "Infrastructure"
            }
          ],
          "text": "Stamp the return address and destination on every piece"
        },
        {
          "alignment": "partial",
          "consequence": "The middle pieces are found in a warehouse with no labels. The delivery fails halfway.",
          "id": "s2_b",
          "metricEffects": [
            {
              "effect": "neutral",
              "metric": "Infrastructure"
            },
            {
              "effect": "negative",
              "metric": "Reliability"
            }
          ],
          "text": "Label only the first and last envelopes"
        },
        {
          "alignment": "weak",
          "consequence": "The mail carrier has no idea where these belong. They end up in the trash.",
          "id": "s2_c",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Reliability"
            },
            {
              "effect": "negative",
              "metric": "Speed"
            }
          ],
          "text": "Write 'Deliver to Client' on the outer bag only"
        }
      ],
      "situation": "The pieces are ready, but the sorter is jammed. You need to ensure they don't get lost if separated."
    },
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "The pieces scatter across the city, but they all eventually arrive at the same door.",
          "id": "s3_a",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Speed"
            },
            {
              "effect": "positive",
              "metric": "Infrastructure"
            }
          ],
          "text": "Tell couriers to take any open path toward the destination"
        },
        {
          "alignment": "partial",
          "consequence": "The delivery is safe, but the client is furious about the long delay.",
          "id": "s3_b",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Speed"
            },
            {
              "effect": "positive",
              "metric": "Reliability"
            }
          ],
          "text": "Wait for the main bridge to be repaired"
        },
        {
          "alignment": "weak",
          "consequence": "A massive traffic jam forms on the side street. Your delivery stops moving entirely.",
          "id": "s3_c",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Infrastructure"
            },
            {
              "effect": "negative",
              "metric": "Speed"
            }
          ],
          "text": "Force all couriers down the same narrow side street"
        }
      ],
      "situation": "The main bridge on the usual route has collapsed. Three couriers are waiting for new instructions."
    },
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "The delivery arrives intact. The client sees exactly what they paid for.",
          "id": "s4_a",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Reliability"
            },
            {
              "effect": "neutral",
              "metric": "Speed"
            }
          ],
          "text": "Keep the contents as they are, despite the weight"
        },
        {
          "alignment": "partial",
          "consequence": "The client receives a blurry video with missing frames. It's barely usable.",
          "id": "s4_b",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Speed"
            },
            {
              "effect": "negative",
              "metric": "Reliability"
            }
          ],
          "text": "Remove some of the file's data to lighten the load"
        },
        {
          "alignment": "weak",
          "consequence": "The envelopes arrive, but they are empty. You've delivered nothing.",
          "id": "s4_c",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Reliability"
            },
            {
              "effect": "positive",
              "metric": "Speed"
            }
          ],
          "text": "Strip the contents to make the envelopes travel faster"
        }
      ],
      "situation": "A courier suggests removing the 'inner contents' to make the envelopes lighter and faster."
    },
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "A tiny note arrives back from the client. Now you know the job is done.",
          "id": "s5_a",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Reliability"
            },
            {
              "effect": "positive",
              "metric": "Speed"
            }
          ],
          "text": "Ask the client for a 'received' note"
        },
        {
          "alignment": "partial",
          "consequence": "The customer is annoyed by the double delivery, and your costs skyrocket.",
          "id": "s5_b",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Reliability"
            },
            {
              "effect": "negative",
              "metric": "Infrastructure"
            }
          ],
          "text": "Send a second copy of everything just in case"
        },
        {
          "alignment": "weak",
          "consequence": "Hours later, you find out the most important piece never arrived. The job failed.",
          "id": "s5_c",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Reliability"
            },
            {
              "effect": "neutral",
              "metric": "Speed"
            }
          ],
          "text": "Assume it worked and close the file"
        }
      ],
      "situation": "The pieces have reached the destination city, but you aren't sure if the client got them all."
    }
  ]
}

{
  "intro": "Você assume o controle da central de dados de uma frota de drones. O sistema está instável e os dados de telemetria precisam de organização imediata.",
  "metrics": [
    "Precisão",
    "Desempenho",
    "Estabilidade"
  ],
  "steps": [
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "O sistema processa as entregas rapidamente e a distância é calculada com precisão decimal. Tudo funciona perfeitamente.",
          "id": "s1_c1",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Precisão"
            },
            {
              "effect": "positive",
              "metric": "Desempenho"
            }
          ],
          "text": "Use números inteiros para entregas e decimais para a distância."
        },
        {
          "alignment": "weak",
          "consequence": "O sistema fica lento tentando processar números complexos para contagens simples. O processador esquenta.",
          "id": "s1_c2",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Desempenho"
            },
            {
              "effect": "negative",
              "metric": "Estabilidade"
            }
          ],
          "text": "Trate todos os números como se tivessem partes imaginárias."
        },
        {
          "alignment": "partial",
          "consequence": "A distância perde a precisão dos metros e o drone começa a errar os pousos por centímetros.",
          "id": "s1_c3",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Precisão"
            },
            {
              "effect": "neutral",
              "metric": "Estabilidade"
            }
          ],
          "text": "Converta todos os valores para números inteiros sem decimais."
        }
      ],
      "situation": "O drone conta as entregas feitas, mas também registra a distância exata em metros. Como você deve armazenar esses dois tipos de dados?"
    },
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "A soma ocorre instantaneamente. O sistema entende cada sinal 'ligado' como o valor um.",
          "id": "s2_c1",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Desempenho"
            }
          ],
          "text": "Some os sinais lógicos diretamente como se fossem números."
        },
        {
          "alignment": "partial",
          "consequence": "O código fica gigante e difícil de ler, embora o resultado final da soma esteja correto.",
          "id": "s2_c2",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Desempenho"
            },
            {
              "effect": "positive",
              "metric": "Precisão"
            }
          ],
          "text": "Crie uma condição para converter cada 'ligado' no número um."
        },
        {
          "alignment": "weak",
          "consequence": "O sistema tenta somar palavras e trava completamente. Você precisa reiniciar o servidor.",
          "id": "s2_c3",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Estabilidade"
            }
          ],
          "text": "Guarde os sinais como texto e conte as letras."
        }
      ],
      "situation": "Os sensores de bateria enviam sinais de 'Ligado' ou 'Desligado'. Você precisa somar quantos drones estão ativos agora."
    },
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "O sistema ignora a leitura sem gerar erros. O gráfico de telemetria mostra um espaço vazio corretamente.",
          "id": "s3_c1",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Estabilidade"
            },
            {
              "effect": "positive",
              "metric": "Precisão"
            }
          ],
          "text": "Atribua o valor nulo à leitura do sensor."
        },
        {
          "alignment": "weak",
          "consequence": "O sistema acha que está fazendo 0 graus. O aquecimento de emergência é ligado sem necessidade.",
          "id": "s3_c2",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Precisão"
            }
          ],
          "text": "Defina o valor da temperatura como zero."
        },
        {
          "alignment": "partial",
          "consequence": "Os cálculos de média ficam absurdos. O sistema não entende que -999 é um erro.",
          "id": "s3_c3",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Precisão"
            },
            {
              "effect": "neutral",
              "metric": "Estabilidade"
            }
          ],
          "text": "Use um número negativo extremo para marcar a falha."
        }
      ],
      "situation": "Um drone atravessa uma zona de sombra e o sensor de temperatura para de responder. Como registrar que não há dado disponível?"
    },
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "A interferência é filtrada perfeitamente usando as duas partes do número. O drone recupera o sinal.",
          "id": "s4_c1",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Precisão"
            },
            {
              "effect": "positive",
              "metric": "Estabilidade"
            }
          ],
          "text": "Use o tipo numérico específico para partes reais e imaginárias."
        },
        {
          "alignment": "partial",
          "consequence": "Os cálculos ficam complexos demais e o drone responde com atraso aos comandos.",
          "id": "s4_c2",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Desempenho"
            },
            {
              "effect": "positive",
              "metric": "Precisão"
            }
          ],
          "text": "Crie duas listas de números decimais para separar as partes."
        },
        {
          "alignment": "weak",
          "consequence": "A falta da parte imaginária faz o drone perder a sincronia. Ele começa a voar em círculos.",
          "id": "s4_c3",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Precisão"
            },
            {
              "effect": "negative",
              "metric": "Estabilidade"
            }
          ],
          "text": "Ignore a parte imaginária e use apenas números inteiros."
        }
      ],
      "situation": "A antena de rádio sofre interferência. Você recebe dados com componentes reais e imaginários simultaneamente para processar."
    },
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "A memória é gerida de forma limpa. O sistema descarta o valor antigo e usa o novo objeto.",
          "id": "s5_c1",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Desempenho"
            },
            {
              "effect": "positive",
              "metric": "Estabilidade"
            }
          ],
          "text": "Atribua o novo valor à variável, criando um novo objeto."
        },
        {
          "alignment": "weak",
          "consequence": "O sistema gera um erro fatal de proteção de memória. O drone começa a cair.",
          "id": "s5_c2",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Estabilidade"
            }
          ],
          "text": "Tente modificar o conteúdo interno do número original."
        },
        {
          "alignment": "partial",
          "consequence": "Muitas variáveis inúteis são criadas. O sistema consome memória desnecessária rapidamente.",
          "id": "s5_c3",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Desempenho"
            }
          ],
          "text": "Guarde cada pequena alteração em uma nova variável diferente."
        }
      ],
      "situation": "A altitude mudou de 100 para 150 metros. Você precisa atualizar essa informação na memória do sistema."
    }
  ]
}

{
  "intro": "Estás en el laboratorio de síntesis orgánica. Debes transformar una cetona valiosa en un nuevo compuesto antes de que termine tu turno o perderás la muestra.",
  "metrics": [
    "Rendimiento",
    "Pureza",
    "Estabilidad"
  ],
  "steps": [
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "Se forma un intermediario cargado muy reactivo. El color de la mezcla cambia a un naranja vibrante rápidamente.",
          "id": "s1_c1",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Rendimiento"
            },
            {
              "effect": "neutral",
              "metric": "Estabilidad"
            }
          ],
          "text": "Añade una base fuerte para arrancar el hidrógeno"
        },
        {
          "alignment": "partial",
          "consequence": "La reacción avanza, pero mucho más lento. Se forma una versión neutra que apenas reacciona con los demás componentes.",
          "id": "s1_c2",
          "metricEffects": [
            {
              "effect": "neutral",
              "metric": "Rendimiento"
            },
            {
              "effect": "positive",
              "metric": "Pureza"
            }
          ],
          "text": "Añade un ácido para reorganizar los enlaces"
        },
        {
          "alignment": "weak",
          "consequence": "No sucede nada en el matraz. Estás perdiendo tiempo valioso mientras el material se degrada por el calor.",
          "id": "s1_c3",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Rendimiento"
            },
            {
              "effect": "negative",
              "metric": "Estabilidad"
            }
          ],
          "text": "Solo aumenta la temperatura del agitador"
        }
      ],
      "situation": "Tienes la cetona en el matraz. Para que empiece a reaccionar, necesitas activar el carbono junto al oxígeno de inmediato."
    },
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "El metal pequeño se une fuertemente al oxígeno. El intermediario se vuelve sorprendentemente estable y fácil de manejar.",
          "id": "s2_c1",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Estabilidad"
            },
            {
              "effect": "positive",
              "metric": "Pureza"
            }
          ],
          "text": "Emplea una base que contenga litio"
        },
        {
          "alignment": "partial",
          "consequence": "El metal ayuda, pero la unión es débil. El intermediario tiende a reaccionar consigo mismo si no tienes cuidado.",
          "id": "s2_c2",
          "metricEffects": [
            {
              "effect": "neutral",
              "metric": "Estabilidad"
            },
            {
              "effect": "negative",
              "metric": "Pureza"
            }
          ],
          "text": "Emplea una base que contenga sodio"
        },
        {
          "alignment": "weak",
          "consequence": "Sin un metal que coordine la carga, el intermediario se descompone. El matraz se llena de un residuo negro alquitranado.",
          "id": "s2_c3",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Pureza"
            },
            {
              "effect": "negative",
              "metric": "Rendimiento"
            }
          ],
          "text": "Usa una base orgánica sin metales"
        }
      ],
      "situation": "El intermediario que has creado es muy inestable. Necesitas un metal que se coordine bien con el oxígeno para proteger la carga negativa."
    },
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "La reacción se aquieta. Ahora puedes elegir exactamente dónde quieres que ocurra el siguiente cambio químico.",
          "id": "s3_c1",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Pureza"
            },
            {
              "effect": "neutral",
              "metric": "Rendimiento"
            }
          ],
          "text": "Sumerge el matraz en hielo seco"
        },
        {
          "alignment": "partial",
          "consequence": "La mezcla sigue burbujeando. Tendrás una mezcla de productos diferentes al final del proceso.",
          "id": "s3_c2",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Pureza"
            },
            {
              "effect": "positive",
              "metric": "Rendimiento"
            }
          ],
          "text": "Mantén la mezcla a temperatura ambiente"
        },
        {
          "alignment": "weak",
          "consequence": "La reacción se sale de control. Una nube de vapor sale del matraz y el rendimiento cae en picado.",
          "id": "s3_c3",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Rendimiento"
            },
            {
              "effect": "negative",
              "metric": "Estabilidad"
            }
          ],
          "text": "Calienta un poco más para terminar rápido"
        }
      ],
      "situation": "El laboratorio se calienta y la reacción se acelera peligrosamente. Podrías perder el control sobre qué parte de la molécula reacciona."
    },
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "La base arranca el hidrógeno más accesible. Obtienes el producto deseado con una precisión casi perfecta.",
          "id": "s4_c1",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Pureza"
            },
            {
              "effect": "positive",
              "metric": "Rendimiento"
            }
          ],
          "text": "Ataca el lado con menos estorbos"
        },
        {
          "alignment": "partial",
          "consequence": "La reacción es forzada y lenta. Solo una pequeña fracción de la muestra logra transformarse correctamente.",
          "id": "s4_c2",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Rendimiento"
            },
            {
              "effect": "neutral",
              "metric": "Pureza"
            }
          ],
          "text": "Intenta que reaccione el lado más congestionado"
        },
        {
          "alignment": "weak",
          "consequence": "Se generan subproductos extraños que son imposibles de separar después. Tu jefe no estará contento con este desorden.",
          "id": "s4_c3",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Pureza"
            },
            {
              "effect": "negative",
              "metric": "Estabilidad"
            }
          ],
          "text": "Deja que la reacción elija el lugar"
        }
      ],
      "situation": "Tu molécula tiene dos lados: uno muy espacioso y otro lleno de grupos químicos que estorban. Debes decidir dónde actuar bajo el frío intenso."
    },
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "La molécula recupera su equilibrio. El producto final precipita como un cristal blanco purísimo.",
          "id": "s5_c1",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Estabilidad"
            },
            {
              "effect": "positive",
              "metric": "Pureza"
            }
          ],
          "text": "Agrega una fuente de protones suave"
        },
        {
          "alignment": "partial",
          "consequence": "Al no cerrar el proceso, la sustancia se oxida al contacto con el aire. La pureza baja drásticamente.",
          "id": "s5_c2",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Pureza"
            },
            {
              "effect": "negative",
              "metric": "Estabilidad"
            }
          ],
          "text": "Filtra la mezcla tal como está"
        },
        {
          "alignment": "weak",
          "consequence": "El calor destruye la estructura que tanto te costó armar. Solo queda un líquido aceitoso inútil.",
          "id": "s5_c3",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Rendimiento"
            },
            {
              "effect": "negative",
              "metric": "Estabilidad"
            }
          ],
          "text": "Evapora el disolvente al vacío"
        }
      ],
      "situation": "La estructura ya está armada, pero sigue siendo un ion muy reactivo. Debes estabilizarla para obtener el producto final neutro."
    }
  ]
}

{
  "intro": "You are the Chief Economic Planner for the Midland Region. A national downturn is looming, and your phone is ringing with conflicting reports from factory owners and retailers.",
  "metrics": [
    "State Budget",
    "Employment",
    "Public Confidence"
  ],
  "steps": [
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "The factories stabilize, saving thousands of blue-collar jobs that would have been lost first. You caught the most volatile sector before it collapsed.",
          "id": "step_1_strong",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "State Budget"
            },
            {
              "effect": "positive",
              "metric": "Employment"
            },
            {
              "effect": "positive",
              "metric": "Public Confidence"
            }
          ],
          "text": "Prioritize aid for heavy manufacturing plants"
        },
